if (!$PreScan.result || !$PreScan.result.trim()) {
    throw new Error(
        "PreScan produced no output (exitcode=" + $PreScan.exitcode + ", error=" + $PreScan.error +
        ") - likely the SSH block's inactivity timeout fired before the trivy scan finished writing " +
        "its output file. Check the timeout input on the PreScan block."
    );
}
const report = JSON.parse($PreScan.result);
const found = [];
for (const result of (report.Results || [])) {
    if (result.Class !== "os-pkgs") continue;
    for (const vuln of (result.Vulnerabilities || [])) {
        if (vuln.FixedVersion) {
            found.push({id: vuln.VulnerabilityID, pkg: vuln.PkgName});
        }
    }
}
$pre_vuln_ids = found.map(f => f.id);
$vulnerable_packages = [...new Set(found.map(f => f.pkg))].sort();

then.function:
function csvEscape(value) {
    const str = (value === undefined || value === null) ? "" : String(value);
    return '"' + str.replace(/"/g, '""') + '"';
}

function extractScore(vuln) {
    const cvss = vuln.CVSS || {};
    for (const source of Object.keys(cvss)) {
        const entry = cvss[source] || {};
        if (typeof entry.V3Score === "number") return entry.V3Score;
        if (typeof entry.V2Score === "number") return entry.V2Score;
    }
    return "";
}

if (!$PostScanJson.result || !$PostScanJson.result.trim()) {
    throw new Error(
        "PostScanJson produced no output (exitcode=" + $PostScanJson.exitcode + ", error=" + $PostScanJson.error +
        ") - likely the SSH block's inactivity timeout fired before the trivy scan finished writing " +
        "its output file. Check the timeout input on the PostScanJson block."
    );
}
const postReport = JSON.parse($PostScanJson.result);
const postFixableIds = [];
const csvRows = [];
const header = ["CVE", "Host IPAddress", "Package", "Package Version", "Package Path", "severity", "Score", "hasFix", "Fixed Version", "Description", "Host Name"];
csvRows.push(header.map(csvEscape).join(","));

for (const result of (postReport.Results || [])) {
    if (result.Class !== "os-pkgs") continue;
    for (const vuln of (result.Vulnerabilities || [])) {
        if (vuln.FixedVersion) {
            postFixableIds.push(vuln.VulnerabilityID);
        }
        csvRows.push([
            vuln.VulnerabilityID,
            $target_host,
            vuln.PkgName,
            vuln.InstalledVersion,
            "",
            (vuln.Severity || "").toLowerCase(),
            extractScore(vuln),
            vuln.FixedVersion ? "Y" : "N",
            vuln.FixedVersion || "",
            vuln.Description,
            $target_host
        ].map(csvEscape).join(","));
    }
}

const postIds = new Set(postFixableIds);
$resolved_ids = $pre_vuln_ids.filter(id => !postIds.has(id));
$still_present_ids = $pre_vuln_ids.filter(id => postIds.has(id));
$remediation_ok = $still_present_ids.length === 0;

$vm_scan_csv = csvRows.join("\n");
$metadata_str = JSON.stringify({scanner_name: "concert"});

const found = ($FindActions.result && $FindActions.result.actions) || [];
$action_updates = found.map(a => ({
    action_id: a.actions_identifier,
    status: $remediation_ok ? "success" : "failed",
    comments: "Auto-updated by Remediate_SSH_Host"
}));
